import pandas as pd
import numpy as np
from typing import Dict, List
from src.core import WorldState, Ticker

def calculate_dynamic_signals(state: WorldState, history: Dict[str, List[Ticker]]) -> Dict[str, float]:
    signals = {}
    gemini_buy = 0.0
    gemini_sell = 0.0

    for symbol, tickers in history.items():
        if len(tickers) < 20:
            continue

        df = pd.DataFrame([t.model_dump() for t in tickers])
        curr_price = df['close'].iloc[-1]

        # Fast ROC (Rate of Change) to detect immediate micro-impulses
        roc_short = (curr_price - df['close'].shift(2).iloc[-1]) / df['close'].shift(2).iloc[-1]
        roc_long = (curr_price - df['close'].shift(10).iloc[-1]) / df['close'].shift(10).iloc[-1]

        # Order Flow proxy via Price Change / Volatility
        vol = df['close'].pct_change().std()

        # Hyper-aggressive signal forcing logic
        # We bias towards momentum if roc_short exceeds volatility threshold
        if roc_short > (vol * 0.5):
            gemini_buy = 1.0
            gemini_sell = 0.0
        elif roc_short < -(vol * 0.5):
            gemini_buy = 0.0
            gemini_sell = 1.0
        else:
            # Fallback to mean reversion based on ROC spread to ensure 60s coverage
            if roc_short > roc_long:
                gemini_buy = 1.0
            else:
                gemini_sell = 1.0

    return {"gemini_buy": float(gemini_buy), "gemini_sell": float(gemini_sell)}
